files_to_modify.find:
// HTML should be newer than (or same as) wins.json
const htmlStat = fs.statSync(HTML_PATH);
const winsStat = fs.statSync(WINS_PATH);
assert(htmlStat.mtimeMs >= winsStat.mtimeMs - 1000,
  'HTML is not stale (modified after or with wins.json)');

files_to_modify.replace:
// PROP-033: replaced mtime assertion with deterministic content-equivalence
// check. The mtime check was a proxy for 'someone rebuilt after editing data',
// but workspace-sync's universal-pusher writes data/wins.json to FUSE without
// also writing the rebuilt docs/index.html, making mtime an unreliable signal
// (false-positive 2026-05-13T01:16Z). Content-equivalence is direct: if the
// committed docs/index.html is byte-identical to a fresh build from current
// data files, it is by definition not stale, regardless of mtime.
const { execSync } = require('child_process');
try {
  const fresh = execSync('node build.js html --quiet --to=/tmp/test-build-' + process.pid + '.html 2>/dev/null && md5sum /tmp/test-build-' + process.pid + '.html | cut -d" " -f1').toString().trim();
  const current = execSync('md5sum ' + HTML_PATH + ' | cut -d" " -f1').toString().trim();
  execSync('rm -f /tmp/test-build-' + process.pid + '.html').toString();
  assert(fresh === current, 'HTML matches a fresh build from current data files (no rebuild needed)');
} catch (e) {
  // Fall back to mtime check if --to flag isn't supported; document the fallback.
  const htmlStat = fs.statSync(HTML_PATH);
  const winsStat = fs.statSync(WINS_PATH);
  assert(htmlStat.mtimeMs >= winsStat.mtimeMs - 1000,
    'HTML is not stale (modified after or with wins.json) — fallback mtime check; build.js html --to flag missing');
}
